from itertools import combinations, permutations

class Solution:
    def countTrapezoids(self, points):
        MOD = 10**9 + 7
        def cross(o, a, b):
            return (a[0]-o[0])*(b[1]-o[1]) - (a[1]-o[1])*(b[0]-o[0])
        def convex(q):
            signs = []
            for i in range(4):
                c = cross(q[i], q[(i+1) % 4], q[(i+2) % 4])
                if c == 0:
                    return False
                signs.append(c > 0)
            return all(signs) or not any(signs)
        def horiz_pair(q):
            for i in range(4):
                a, b = q[i], q[(i+1) % 4]
                c, d = q[(i+2) % 4], q[(i+3) % 4]
                if a[1] == b[1] and c[1] == d[1]:
                    return True
            return False
        cnt = 0
        for four in combinations(points, 4):
            for perm in permutations(four):
                p = list(perm)
                if convex(p) and horiz_pair(p):
                    cnt += 1
                    break
        return cnt % MOD

