var countTrapezoids = function(points) {
    const MOD = 1000000007n;
    const byY = new Map();
    for (const [, y] of points) byY.set(y, (byY.get(y) || 0) + 1);
    const seg = [];
    for (const c of byY.values()) {
        const bc = BigInt(c);
        seg.push((bc * (bc - 1n)) / 2n);
    }
    let tot = 0n;
    for (const s of seg) tot += s;
    let ans = 0n;
    for (const s of seg) ans += s * (tot - s);
    ans = ans / 2n;
    return Number(ans % MOD);
};
